import{_ as t,c as r,o as s,ag as i}from"./chunks/framework.DRADY2L-.js";const d=JSON.parse('{"title":"Useful LUA Scripts for Radios","description":"Various scripts exist for configuring your radio, drone, transmitter, and receiver, as well as for viewing logs and even playing simple games. These scripts ...","frontmatter":{"description":"Various scripts exist for configuring your radio, drone, transmitter, and receiver, as well as for viewing logs and even playing simple games. These scripts ...","gitAuthors":["mituritsyn","ikherty","Valentina Petrenko"]},"headers":[],"relativePath":"settings/scripts.md","filePath":"en/settings/scripts.md","lastUpdated":1771019108000}'),a={name:"settings/scripts.md"};function o(l,e,n,c,p,f){return s(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="useful-lua-scripts-for-radios" tabindex="-1">Useful LUA Scripts for Radios <a class="header-anchor" href="#useful-lua-scripts-for-radios" aria-label="Permalink to &quot;Useful LUA Scripts for Radios&quot;">​</a></h1><p>Various scripts exist for configuring your radio, drone, transmitter, and receiver, as well as for viewing logs and even playing simple games. These scripts are typically placed in the <code>scripts/tools</code> folder on the radio&#39;s SD card. I recommend checking out the essential scripts listed below.</p><h2 id="essential-scripts-for-most-pilots" tabindex="-1">Essential Scripts for Most Pilots <a class="header-anchor" href="#essential-scripts-for-most-pilots" aria-label="Permalink to &quot;Essential Scripts for Most Pilots&quot;">​</a></h2><ul><li><p><a href="https://github.com/betaflight/betaflight-tx-lua-scripts" target="_blank" rel="noreferrer">Betaflight LUA Script</a> If telemetry is available from your drone&#39;s receiver, you can adjust most Betaflight settings directly from your radio without connecting to a computer. Don&#39;t forget to save your changes!</p></li><li><p><a href="https://www.expresslrs.org/quick-start/transmitters/lua-howto/" target="_blank" rel="noreferrer">ExpressLRS Configurator (if using an ELRS radio system)</a> It is important to use the LUA script version matches your ELRS transmitter version (v2 script for hardware version 2.<em>.</em>, v3 script for 3.<em>.</em>).</p></li><li><p><a href="https://www.team-blacksheep.com/products/prod:agentx" target="_blank" rel="noreferrer">TBS Agent Lite (for Crossfire/Tracer radio systems)</a></p></li></ul><h2 id="optional-scripts" tabindex="-1">Optional Scripts <a class="header-anchor" href="#optional-scripts" aria-label="Permalink to &quot;Optional Scripts&quot;">​</a></h2><ul><li><p><a href="https://github.com/alexeystn/lua-fpv-sim" target="_blank" rel="noreferrer">FPV Simulator Script by AlexeyStn</a> One of the top racing pilots in Russia, AlexeyStn, created this script that allows you to practice flying if you only have your radio handy.</p></li><li><p><a href="https://github.com/EdgeTX/lua-scripts" target="_blank" rel="noreferrer">Multi-script Collection</a> A large collection of various LUA scripts for EdgeTX.</p></li></ul>',6)])])}const h=t(a,[["render",o]]);export{d as __pageData,h as default};
